/**
 * TransitionPicker — Componente para seleção de transições entre slides
 *
 * Exibe grid de presets com preview animado de cada tipo,
 * slider de duração (0.3s→2.0s), e indicador visual da transição ativa.
 *
 * Todas as funções de formatação são puras e exportadas para testes.
 */

'use client';

import React, { useState, useCallback, useEffect, useRef } from 'react';
import { Button } from '@components/ui/button';
import { Slider } from '@components/ui/slider';
import { ScrollArea } from '@components/ui/scroll-area';
import { Separator } from '@components/ui/separator';
import { Label } from '@components/ui/label';
import { Badge } from '@components/ui/badge';
import { cn } from '@lib/utils';
import {
  Ban,
  Sun,
  Sparkles,
  ArrowLeft,
  ArrowRight,
  ArrowUp,
  ArrowDown,
  ZoomIn,
  ArrowRightFromLine,
  ArrowLeftFromLine,
  Check,
  Play,
  RotateCcw,
} from 'lucide-react';

import {
  type TransitionType,
  type TransitionPreset,
  type TransitionConfig,
  TRANSITION_PRESETS,
  MIN_DURATION,
  MAX_DURATION,
  DEFAULT_DURATION,
  getPresetsByCategory,
  getCategoryLabel,
  buildTransitionConfig,
  computeTransitionStyle,
  computeWipeClipPath,
  clampDuration,
} from '@/lib/render/transitions';

// ============================================================================
// PURE UTILITY FUNCTIONS (exported for testing)
// ============================================================================

/**
 * Format duration in seconds to display string (e.g., "0.5s").
 */
export function formatDurationLabel(seconds: number): string {
  return `${seconds.toFixed(1)}s`;
}

/**
 * Convert slider value (0–100) to duration in seconds.
 */
export function sliderToDuration(sliderValue: number): number {
  const ratio = sliderValue / 100;
  return clampDuration(MIN_DURATION + ratio * (MAX_DURATION - MIN_DURATION));
}

/**
 * Convert duration in seconds to slider value (0–100).
 */
export function durationToSlider(duration: number): number {
  if (duration <= 0) return 0;
  const clamped = clampDuration(duration);
  return Math.round(((clamped - MIN_DURATION) / (MAX_DURATION - MIN_DURATION)) * 100);
}

/**
 * Get the Lucide icon component for a preset based on its icon hint.
 */
export function getPresetIcon(iconHint: string): React.ElementType {
  const iconMap: Record<string, React.ElementType> = {
    ban: Ban,
    sun: Sun,
    sparkles: Sparkles,
    arrowLeft: ArrowLeft,
    arrowRight: ArrowRight,
    arrowUp: ArrowUp,
    arrowDown: ArrowDown,
    zoomIn: ZoomIn,
    arrowRightFromLine: ArrowRightFromLine,
    arrowLeftFromLine: ArrowLeftFromLine,
  };
  return iconMap[iconHint] ?? Sun;
}

/**
 * Build summary text for a transition config.
 */
export function buildSummaryText(config: TransitionConfig): string {
  if (config.type === 'none') return 'Sem transição';
  const preset = TRANSITION_PRESETS.find((p) => p.type === config.type);
  const label = preset?.label ?? config.type;
  return `${label} · ${formatDurationLabel(config.duration)}`;
}

// ============================================================================
// MINI PREVIEW SUB-COMPONENT
// ============================================================================

interface MiniPreviewProps {
  type: TransitionType;
  isPlaying: boolean;
}

function MiniPreview({ type, isPlaying }: MiniPreviewProps) {
  const [progress, setProgress] = useState(0);
  const rafRef = useRef<number>(0);
  const startRef = useRef(0);

  useEffect(() => {
    if (!isPlaying) {
      setProgress(0);
      return;
    }

    startRef.current = performance.now();
    const duration = 800; // ms for preview animation

    const animate = (now: number) => {
      const elapsed = now - startRef.current;
      const t = Math.min(elapsed / duration, 1);
      setProgress(t);
      if (t < 1) {
        rafRef.current = requestAnimationFrame(animate);
      }
    };

    rafRef.current = requestAnimationFrame(animate);
    return () => {
      if (rafRef.current) cancelAnimationFrame(rafRef.current);
    };
  }, [isPlaying]);

  const style = computeTransitionStyle(type, progress, 48, 32);
  const clipPath = computeWipeClipPath(type, progress);

  return (
    <div className="w-12 h-8 rounded-sm overflow-hidden relative bg-muted/50 border border-border/50">
      {/* Background (outgoing scene) */}
      <div className="absolute inset-0 bg-gradient-to-br from-primary/30 to-primary/10" />
      {/* Incoming scene */}
      <div
        className="absolute inset-0 bg-gradient-to-br from-blue-500/60 to-blue-400/30"
        style={{
          opacity: style.opacity,
          transform: style.transform,
          clipPath: clipPath ?? undefined,
          transition: 'none',
        }}
      />
    </div>
  );
}

// ============================================================================
// PRESET CARD SUB-COMPONENT
// ============================================================================

interface PresetCardProps {
  preset: TransitionPreset;
  isSelected: boolean;
  onSelect: (type: TransitionType) => void;
}

function PresetCard({ preset, isSelected, onSelect }: PresetCardProps) {
  const [hovering, setHovering] = useState(false);
  const Icon = getPresetIcon(preset.icon);

  return (
    <button
      type="button"
      className={cn(
        'flex flex-col items-center gap-1 p-2 rounded-md border text-xs',
        'hover:bg-accent/50 focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring',
        'transition-colors duration-150 cursor-pointer',
        isSelected
          ? 'border-primary bg-primary/10 text-primary'
          : 'border-border/50 text-muted-foreground',
      )}
      onClick={() => onSelect(preset.type)}
      onMouseEnter={() => setHovering(true)}
      onMouseLeave={() => setHovering(false)}
      title={preset.description}
    >
      <div className="relative">
        <MiniPreview type={preset.type} isPlaying={hovering || isSelected} />
        {isSelected && (
          <div className="absolute -top-1 -right-1 w-3.5 h-3.5 rounded-full bg-primary flex items-center justify-center">
            <Check className="w-2 h-2 text-primary-foreground" />
          </div>
        )}
      </div>
      <div className="flex items-center gap-1">
        <Icon className="w-3 h-3" />
        <span className="truncate max-w-[60px]">{preset.label}</span>
      </div>
    </button>
  );
}

// ============================================================================
// MAIN COMPONENT
// ============================================================================

export interface TransitionPickerProps {
  /** Index of the scene (used in label) */
  sceneIndex: number;
  /** Scene name (for labeling) */
  sceneName?: string;
  /** Current transition config */
  value: TransitionConfig;
  /** Callback when config changes */
  onChange: (config: TransitionConfig) => void;
  /** Additional CSS class */
  className?: string;
}

export default function TransitionPicker({
  sceneIndex,
  sceneName,
  value,
  onChange,
  className,
}: TransitionPickerProps) {
  const [previewPlaying, setPreviewPlaying] = useState(false);
  const [previewKey, setPreviewKey] = useState(0);

  const grouped = getPresetsByCategory();

  const handleSelectType = useCallback(
    (type: TransitionType) => {
      const config = buildTransitionConfig(type, type === value.type ? value.duration : undefined);
      onChange(config);
    },
    [value, onChange],
  );

  const handleDurationChange = useCallback(
    (sliderValues: number[]) => {
      const dur = sliderToDuration(sliderValues[0]);
      onChange(buildTransitionConfig(value.type, dur));
    },
    [value.type, onChange],
  );

  const handlePlayPreview = useCallback(() => {
    setPreviewPlaying(false);
    setPreviewKey((k) => k + 1);
    // Small delay to restart the animation
    requestAnimationFrame(() => setPreviewPlaying(true));
  }, []);

  const handleReset = useCallback(() => {
    onChange(buildTransitionConfig('none'));
    setPreviewPlaying(false);
  }, [onChange]);

  const sliderValue = durationToSlider(value.duration);

  return (
    <div className={cn('flex flex-col gap-3', className)}>
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2 min-w-0">
          <Label className="text-xs font-medium truncate">
            {sceneName
              ? `Transição: ${sceneName}`
              : `Transição antes do Slide ${sceneIndex + 1}`}
          </Label>
        </div>
        <Badge variant="outline" className="text-[10px] shrink-0">
          {buildSummaryText(value)}
        </Badge>
      </div>

      {/* Preset Grid by Category */}
      <ScrollArea className="max-h-[240px]">
        <div className="space-y-3 pr-2">
          {Object.entries(grouped).map(([category, presets]) => (
            <div key={category}>
              <p className="text-[10px] font-medium text-muted-foreground uppercase tracking-wider mb-1.5">
                {getCategoryLabel(category)}
              </p>
              <div className="grid grid-cols-3 gap-1.5">
                {presets.map((preset) => (
                  <PresetCard
                    key={preset.type}
                    preset={preset}
                    isSelected={value.type === preset.type}
                    onSelect={handleSelectType}
                  />
                ))}
              </div>
            </div>
          ))}
        </div>
      </ScrollArea>

      {/* Duration Slider (only if not 'none') */}
      {value.type !== 'none' && (
        <>
          <Separator />
          <div className="space-y-2">
            <div className="flex items-center justify-between">
              <Label className="text-xs">Duração</Label>
              <span className="text-xs font-mono text-muted-foreground">
                {formatDurationLabel(value.duration)}
              </span>
            </div>
            <Slider
              min={0}
              max={100}
              step={1}
              value={[sliderValue]}
              onValueChange={handleDurationChange}
              className="w-full"
            />
            <div className="flex justify-between text-[10px] text-muted-foreground">
              <span>{formatDurationLabel(MIN_DURATION)}</span>
              <span>{formatDurationLabel(MAX_DURATION)}</span>
            </div>
          </div>
        </>
      )}

      {/* Large Preview */}
      <Separator />
      <div className="space-y-2">
        <div className="flex items-center justify-between">
          <Label className="text-xs">Preview</Label>
          <div className="flex gap-1">
            <Button
              variant="ghost"
              size="icon"
              className="h-6 w-6"
              onClick={handlePlayPreview}
              title="Reproduzir preview"
            >
              <Play className="w-3 h-3" />
            </Button>
            <Button
              variant="ghost"
              size="icon"
              className="h-6 w-6"
              onClick={handleReset}
              title="Remover transição"
            >
              <RotateCcw className="w-3 h-3" />
            </Button>
          </div>
        </div>
        <LargePreview
          key={previewKey}
          type={value.type}
          isPlaying={previewPlaying}
          duration={value.duration}
        />
      </div>
    </div>
  );
}

// ============================================================================
// LARGE PREVIEW SUB-COMPONENT
// ============================================================================

interface LargePreviewProps {
  type: TransitionType;
  isPlaying: boolean;
  duration: number;
}

function LargePreview({ type, isPlaying, duration }: LargePreviewProps) {
  const [progress, setProgress] = useState(0);
  const rafRef = useRef<number>(0);
  const startRef = useRef(0);

  useEffect(() => {
    if (!isPlaying) {
      setProgress(0);
      return;
    }

    startRef.current = performance.now();
    const animDuration = Math.max(400, duration * 1000);

    const animate = (now: number) => {
      const elapsed = now - startRef.current;
      const t = Math.min(elapsed / animDuration, 1);
      setProgress(t);
      if (t < 1) {
        rafRef.current = requestAnimationFrame(animate);
      }
    };

    rafRef.current = requestAnimationFrame(animate);
    return () => {
      if (rafRef.current) cancelAnimationFrame(rafRef.current);
    };
  }, [isPlaying, duration]);

  const style = computeTransitionStyle(type, progress, 200, 112);
  const clipPath = computeWipeClipPath(type, progress);

  return (
    <div className="w-full h-28 rounded-md overflow-hidden relative bg-muted border border-border">
      {/* Outgoing scene */}
      <div className="absolute inset-0 flex items-center justify-center">
        <div className="absolute inset-0 bg-gradient-to-br from-orange-500/20 to-red-500/20" />
        <span className="text-xs text-muted-foreground z-10">Slide anterior</span>
      </div>
      {/* Incoming scene */}
      <div
        className="absolute inset-0 flex items-center justify-center"
        style={{
          opacity: style.opacity,
          transform: style.transform,
          clipPath: clipPath ?? undefined,
          transition: 'none',
        }}
      >
        <div className="absolute inset-0 bg-gradient-to-br from-blue-500/30 to-purple-500/20" />
        <span className="text-xs text-foreground z-10">Slide atual</span>
      </div>
    </div>
  );
}
